index 9df08553d86e..6692eb4c70ac 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,7 +8790,82 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

-  // Convert a sign-bit test of an FP value into a cast and integer compare.
+cat << 'CODEEOF' | python /app/data/auto-opt/utils/llvm-85265/data/auto-opt/utils/llvm-85265/utils/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8793 8793
+  if (match(Op0, m_OneUse(m_FPTrunc(m_Value(X))))) {
+    // fcmp (fptrunc X), C -> fcmp X, C'
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C)) && !C->isNaN()) {
+      // Determine the wider type's semantics
+      const fltSemantics &WideFPSem = X->getType()->getScalarType()->getFltSemantics();
+      const fltSemantics &TruncFPSem = C->getSemantics();
+      // See if C can be losslessly converted to the wider type
+      bool Lossy;
+      APFloat WideC = *C;
+      WideC.convert(WideFPSem, APFloat::rmNearestTiesToEven, &Lossy);
+      if (!Lossy && (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT || Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE)) {
+        APFloat PrevC = *C;
+        bool IsZero = PrevC.isZero() && !PrevC.isNegative();
+        if (!PrevC.isInfinity() && !IsZero) {
+            bool NeedLower = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_ULT);
+            APFloat AdjC = *C;
+            if (NeedLower)
+                AdjC.next(/*nextDown=*/true);
+            else
+                AdjC.next(/*nextDown=*/false);
+            
+            APFloat WideAdjC = AdjC;
+            WideAdjC.convert(WideFPSem, APFloat::rmNearestTiesToEven, &Lossy);
+            APFloat Mid = WideAdjC;
+            Mid.add(WideC, APFloat::rmNearestTiesToEven);
+            APFloat Two(WideFPSem, "2.0");
+            Mid.divide(Two, APFloat::rmNearestTiesToEven);
+            
+            APFloat TruncMid = Mid;
+            TruncMid.convert(TruncFPSem, APFloat::rmNearestTiesToEven, &Lossy);
+            bool RoundsToC = TruncMid.bitwiseIsEqual(*C);
+            
+            if (NeedLower) {
+                if (RoundsToC) {
+                    if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE)
+                        return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT)
+                        return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                } else {
+                    if (Pred == FCmpInst::FCMP_OGE)
+                        return new FCmpInst(FCmpInst::FCMP_OGT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_UGE)
+                        return new FCmpInst(FCmpInst::FCMP_UGT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_OLT)
+                        return new FCmpInst(FCmpInst::FCMP_OLE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_ULT)
+                        return new FCmpInst(FCmpInst::FCMP_ULE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                }
+            } else {
+                if (RoundsToC) {
+                    if (Pred == FCmpInst::FCMP_OGT)
+                        return new FCmpInst(FCmpInst::FCMP_OGT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_UGT)
+                        return new FCmpInst(FCmpInst::FCMP_UGT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_OLE)
+                        return new FCmpInst(FCmpInst::FCMP_OLE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_ULE)
+                        return new FCmpInst(FCmpInst::FCMP_ULE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                } else {
+                    if (Pred == FCmpInst::FCMP_OGT)
+                        return new FCmpInst(FCmpInst::FCMP_OGE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_UGT)
+                        return new FCmpInst(FCmpInst::FCMP_UGE, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_OLE)
+                        return new FCmpInst(FCmpInst::FCMP_OLT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                    if (Pred == FCmpInst::FCMP_ULE)
+                        return new FCmpInst(FCmpInst::FCMP_ULT, X, ConstantFP::get(X->getType(), Mid), "", &I);
+                }
+            }
+        }
+      }
+    }
+  }
+CODEEOF
