import struct
import math

def to_hex(f):
    return hex(struct.unpack('>I', struct.pack('>f', f))[0])

def to_hex_double(d):
    return hex(struct.unpack('>Q', struct.pack('>d', d))[0])

print(to_hex_double(100.0))
# the expected double is 0x4058FFFFF0000000
""}

